class Graph:
    def __init__(self, num_vertices):
        self.num_vertices = num_vertices
        self.adj_matrix = [[0] * num_vertices for _ in range(num_vertices)]

    def add_edge(self, u, v, weight=1):
        if 0 <= u < self.num_vertices and 0 <= v < self.num_vertices:
            self.adj_matrix[u][v] = weight
            self.adj_matrix[v][u] = weight  # For an undirected graph
        else:
            print("Geçersiz köşe indeksi.")

    def print_matrix(self):
        for row in self.adj_matrix:
            print(" ".join(map(str, row)))

if __name__ == '__main__':
    # Örnek kullanım: 4 köşeli bir grafik oluşturma
    g = Graph(4)

    # Kenarları ekleme (varsayılan olarak ağırlıksız ve yönsüz)
    g.add_edge(0, 1)
    g.add_edge(0, 2)
    g.add_edge(1, 2)
    g.add_edge(2, 3)

    # Ağırlıklı bir kenar ekleme örneği
    g.add_edge(1, 3, 5)

    # Komşuluk matrisini yazdırma
    g.print_matrix()
